// Descobre o tipo do arquivo (PDF x planilha) e carrega os metadados do upload.
const item = $input.first();
const bin = (item.binary && item.binary.data) || {};
const name = (bin.fileName || '').toString().toLowerCase();
const mime = (bin.mimeType || '').toString().toLowerCase();
let kind = 'spreadsheet';
if (name.endsWith('.pdf') || mime.includes('pdf')) kind = 'pdf';
const body = ($('Receive Inventory').first().json.body) || {};
return [{
  json: {
    kind,
    arquivo: bin.fileName || 'Registro de Inventário',
    userId: (body.userId || '').toString().trim() || null
  },
  binary: item.binary
}];

// Normaliza as linhas do Registro de Inventário para o formato esperado por
// wl_ingest_inventario (codigo, descricao, quantidade, unidade, valor_unitario, grupo).
// Funciona tanto para planilha (Excel/CSV) quanto para PDF (parser best-effort).
const meta = $('Detect Kind').first().json || {};
const items = $input.all();
const first = items[0] && items[0].json;
const isPdf = items.length === 1 && first && typeof first.text === 'string' && first.text.length > 40;
let rows = [];

if (isPdf) {
  const lines = first.text.split(/\r?\n/);
  let grupo = null;
  const reGrupo = /Grupo de Estoque\s*:?\s*(.+)/i;
  // NCM  codigo - descricao  quantidade  unidade  valor_unit  valor_total
  const reItem = /^([0-9][0-9.]{4,11})\s+(.+?)\s+([0-9.]*[0-9],[0-9]+)\s+([A-Za-z]{1,3})\s+([0-9.]*[0-9],[0-9]+)\s+([0-9.]*[0-9],[0-9]+)\s*$/;
  for (const raw of lines) {
    const line = (raw || '').trim();
    if (!line) continue;
    const g = line.match(reGrupo);
    if (g) { grupo = g[1].trim(); continue; }
    const m = line.match(reItem);
    if (!m) continue;
    const rest = m[2].trim();
    const dash = rest.indexOf(' - ');
    const codigo = dash >= 0 ? rest.slice(0, dash).trim() : rest.split(/\s+/)[0];
    const descricao = dash >= 0 ? rest.slice(dash + 3).trim() : rest;
    rows.push({ codigo, descricao, quantidade: m[3], unidade: m[4], valor_unitario: m[5], grupo });
  }
} else {
  rows = items
    .map((i) => i.json)
    .filter((o) => o && Object.keys(o).length)
    .map((o) => {
      const out = {};
      for (const k of Object.keys(o)) out[k.toString().trim().toLowerCase().replace(/\s+/g, '_')] = o[k];
      return out;
    });
}

return [{ json: { arquivo: meta.arquivo, total_linhas: rows.length, rows } }];
